package com.enterprise.app.repository;

import com.enterprise.app.entity.Transaction;
import com.enterprise.app.enums.TransactionStatus;
import com.enterprise.app.enums.TransactionType;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;

@Repository
public interface TransactionRepository extends JpaRepository<Transaction, Long> {

    Optional<Transaction> findByReferenceNumber(String referenceNumber);

    Page<Transaction> findByUserId(Long userId, Pageable pageable);

    List<Transaction> findByUserIdAndStatus(Long userId, TransactionStatus status);

    Page<Transaction> findByUserIdAndTransactionType(Long userId, TransactionType transactionType, Pageable pageable);

    @Query("SELECT t FROM Transaction t WHERE t.user.id = :userId AND t.createdAt BETWEEN :startDate AND :endDate ORDER BY t.createdAt DESC")
    List<Transaction> findUserTransactionsBetweenDates(
            @Param("userId") Long userId,
            @Param("startDate") LocalDateTime startDate,
            @Param("endDate") LocalDateTime endDate);

    @Query("SELECT SUM(t.amount) FROM Transaction t WHERE t.user.id = :userId AND t.transactionType = :type AND t.status = 'COMPLETED'")
    BigDecimal sumCompletedAmountByUserAndType(@Param("userId") Long userId, @Param("type") TransactionType type);

    @Query("SELECT COUNT(t) FROM Transaction t WHERE t.user.id = :userId AND t.status = :status")
    long countByUserIdAndStatus(@Param("userId") Long userId, @Param("status") TransactionStatus status);

    @Query("SELECT t FROM Transaction t WHERE t.status = :status AND t.createdAt < :cutoffTime")
    List<Transaction> findStaleTransactions(@Param("status") TransactionStatus status, @Param("cutoffTime") LocalDateTime cutoffTime);

    @Query("SELECT t FROM Transaction t WHERE t.user.id = :userId ORDER BY t.createdAt DESC")
    Page<Transaction> findRecentTransactions(@Param("userId") Long userId, Pageable pageable);

    @Query(value = "SELECT DATE(t.created_at) as txn_date, COUNT(*) as txn_count, SUM(t.amount) as total_amount " +
            "FROM transactions t WHERE t.user_id = :userId AND t.status = 'COMPLETED' " +
            "GROUP BY DATE(t.created_at) ORDER BY txn_date DESC", nativeQuery = true)
    List<Object[]> getDailyTransactionSummary(@Param("userId") Long userId);
}


