package com.enterprise.app.service;

import com.enterprise.app.dto.UserCreateRequest;
import com.enterprise.app.dto.UserResponse;
import com.enterprise.app.dto.UserUpdateRequest;
import com.enterprise.app.entity.User;
import com.enterprise.app.enums.UserStatus;
import com.enterprise.app.exception.DuplicateResourceException;
import com.enterprise.app.exception.ResourceNotFoundException;
import com.enterprise.app.repository.UserRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;
import java.util.List;
import java.util.stream.Collectors;

@Service
@Transactional
public class UserService {

    private static final Logger logger = LoggerFactory.getLogger(UserService.class);

    private final UserRepository userRepository;

    public UserService(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    public UserResponse createUser(UserCreateRequest request) {
        logger.info("Creating user with username: {}", request.getUsername());

        if (userRepository.existsByUsername(request.getUsername())) {
            throw new DuplicateResourceException("Username already exists: " + request.getUsername());
        }
        if (userRepository.existsByEmail(request.getEmail())) {
            throw new DuplicateResourceException("Email already exists: " + request.getEmail());
        }

        User user = new User();
        user.setUsername(request.getUsername());
        user.setEmail(request.getEmail());
        user.setFirstName(request.getFirstName());
        user.setLastName(request.getLastName());
        user.setPassword(request.getPassword()); // In production, hash the password
        user.setStatus(UserStatus.ACTIVE);

        User savedUser = userRepository.save(user);
        logger.info("User created successfully with ID: {}", savedUser.getId());
        return UserResponse.fromEntity(savedUser);
    }

    @Transactional(readOnly = true)
    public UserResponse getUserById(Long id) {
        User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User not found with ID: " + id));
        return UserResponse.fromEntity(user);
    }

    @Transactional(readOnly = true)
    public UserResponse getUserByUsername(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new ResourceNotFoundException("User not found with username: " + username));
        return UserResponse.fromEntity(user);
    }

    @Transactional(readOnly = true)
    public Page<UserResponse> getAllUsers(Pageable pageable) {
        return userRepository.findAll(pageable).map(UserResponse::fromEntity);
    }

    @Transactional(readOnly = true)
    public Page<UserResponse> getUsersByStatus(UserStatus status, Pageable pageable) {
        return userRepository.findByStatus(status, pageable).map(UserResponse::fromEntity);
    }

    @Transactional(readOnly = true)
    public Page<UserResponse> searchUsers(String name, Pageable pageable) {
        return userRepository.searchByName(name, pageable).map(UserResponse::fromEntity);
    }

    public UserResponse updateUser(Long id, UserUpdateRequest request) {
        logger.info("Updating user with ID: {}", id);

        User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User not found with ID: " + id));

        if (request.getEmail() != null && !request.getEmail().equals(user.getEmail())) {
            if (userRepository.existsByEmail(request.getEmail())) {
                throw new DuplicateResourceException("Email already exists: " + request.getEmail());
            }
            user.setEmail(request.getEmail());
        }

        if (request.getFirstName() != null) {
            user.setFirstName(request.getFirstName());
        }
        if (request.getLastName() != null) {
            user.setLastName(request.getLastName());
        }

        User updatedUser = userRepository.save(user);
        logger.info("User updated successfully with ID: {}", updatedUser.getId());
        return UserResponse.fromEntity(updatedUser);
    }

    public void activateUser(Long id) {
        logger.info("Activating user with ID: {}", id);
        int updated = userRepository.updateUserStatus(id, UserStatus.ACTIVE, LocalDateTime.now());
        if (updated == 0) {
            throw new ResourceNotFoundException("User not found with ID: " + id);
        }
    }

    public void suspendUser(Long id) {
        logger.info("Suspending user with ID: {}", id);
        int updated = userRepository.updateUserStatus(id, UserStatus.SUSPENDED, LocalDateTime.now());
        if (updated == 0) {
            throw new ResourceNotFoundException("User not found with ID: " + id);
        }
    }

    public void deactivateUser(Long id) {
        logger.info("Deactivating user with ID: {}", id);
        int updated = userRepository.updateUserStatus(id, UserStatus.INACTIVE, LocalDateTime.now());
        if (updated == 0) {
            throw new ResourceNotFoundException("User not found with ID: " + id);
        }
    }

    public void deleteUser(Long id) {
        logger.info("Deleting user with ID: {}", id);
        if (!userRepository.existsById(id)) {
            throw new ResourceNotFoundException("User not found with ID: " + id);
        }
        userRepository.deleteById(id);
        logger.info("User deleted successfully with ID: {}", id);
    }

    public void recordLogin(Long id) {
        userRepository.updateLastLogin(id, LocalDateTime.now());
    }

    @Transactional(readOnly = true)
    public List<UserResponse> getUsersCreatedBetween(LocalDateTime startDate, LocalDateTime endDate) {
        return userRepository.findUsersCreatedBetween(startDate, endDate)
                .stream()
                .map(UserResponse::fromEntity)
                .collect(Collectors.toList());
    }

    @Transactional(readOnly = true)
    public long getUserCountByStatus(UserStatus status) {
        return userRepository.countByStatus(status);
    }
}


// src/main/java/com/enterprise/app/service/TransactionService.java

package com.enterprise.app.service;

import com.enterprise.app.dto.TransactionRequest;
import com.enterprise.app.dto.TransactionResponse;
import com.enterprise.app.entity.Transaction;
import com.enterprise.app.entity.User;
import com.enterprise.app.enums.TransactionStatus;
import com.enterprise.app.enums.TransactionType;
import com.enterprise.app.exception.InsufficientBalanceException;
import com.enterprise.app.exception.ResourceNotFoundException;
import com.enterprise.app.exception.TransactionProcessingException;
import com.enterprise.app.repository.TransactionRepository;
import com.enterprise.app.repository.UserRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Isolation;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.UUID;
import java.util.stream.Collectors;

@Service
public class TransactionService {

    private static final Logger logger = LoggerFactory.getLogger(TransactionService.class);

    private final TransactionRepository transactionRepository;
    private final UserRepository userRepository;

    public TransactionService(TransactionRepository transactionRepository, UserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    @Transactional(isolation = Isolation.SERIALIZABLE)
    public TransactionResponse processTransaction(TransactionRequest request) {
        logger.info("Processing {} transaction for user ID: {}, amount: {}",
                request.getTransactionType(), request.getUserId(), request.getAmount());

        User user = userRepository.findByIdWithLock(request.getUserId())
                .orElseThrow(() -> new ResourceNotFoundException("User not found with ID: " + request.getUserId()));

        Transaction transaction = new Transaction();
        transaction.setReferenceNumber(generateReferenceNumber());
        transaction.setAmount(request.getAmount());
        transaction.setTransactionType(request.getTransactionType());
        transaction.setDescription(request.getDescription());
        transaction.setUser(user);
        transaction.setBalanceBefore(user.getBalance());

        try {
            switch (request.getTransactionType()) {
                case CREDIT:
                    processCredit(user, request.getAmount());
                    break;
                case DEBIT:
                    processDebit(user, request.getAmount());
                    break;
                case TRANSFER:
                    processTransfer(user, request.getAmount(), request.getTargetUserId());
                    transaction.setTargetUserId(request.getTargetUserId());
                    break;
                case REFUND:
                    processCredit(user, request.getAmount());
                    break;
                default:
                    throw new TransactionProcessingException("Unsupported transaction type: " + request.getTransactionType());
            }

            transaction.setBalanceAfter(user.getBalance());
            transaction.setStatus(TransactionStatus.COMPLETED);
            transaction.setCompletedAt(LocalDateTime.now());

            userRepository.save(user);
            Transaction savedTransaction = transactionRepository.save(transaction);

            logger.info("Transaction completed successfully. Reference: {}", savedTransaction.getReferenceNumber());
            return TransactionResponse.fromEntity(savedTransaction);

        } catch (InsufficientBalanceException e) {
            transaction.setStatus(TransactionStatus.FAILED);
            transaction.setFailureReason(e.getMessage());
            transaction.setBalanceAfter(user.getBalance());
            transactionRepository.save(transaction);
            throw e;
        } catch (Exception e) {
            transaction.setStatus(TransactionStatus.FAILED);
            transaction.setFailureReason(e.getMessage());
            transaction.setBalanceAfter(user.getBalance());
            transactionRepository.save(transaction);
            throw new TransactionProcessingException("Failed to process transaction: " + e.getMessage(), e);
        }
    }

    private void processCredit(User user, BigDecimal amount) {
        user.setBalance(user.getBalance().add(amount));
    }

    private void processDebit(User user, BigDecimal amount) {
        if (user.getBalance().compareTo(amount) < 0) {
            throw new InsufficientBalanceException(
                    String.format("Insufficient balance. Available: %s, Required: %s", user.getBalance(), amount));
        }
        user.setBalance(user.getBalance().subtract(amount));
    }

    @Transactional(isolation = Isolation.SERIALIZABLE)
    private void processTransfer(User sourceUser, BigDecimal amount, Long targetUserId) {
        if (targetUserId == null) {
            throw new TransactionProcessingException("Target user ID is required for transfer transactions");
        }

        if (sourceUser.getId().equals(targetUserId)) {
            throw new TransactionProcessingException("Cannot transfer to the same account");
        }

        User targetUser = userRepository.findByIdWithLock(targetUserId)
                .orElseThrow(() -> new ResourceNotFoundException("Target user not found with ID: " + targetUserId));

        processDebit(sourceUser, amount);
        processCredit(targetUser, amount);

        userRepository.save(targetUser);
    }

    @Transactional(readOnly = true)
    public TransactionResponse getTransactionByReference(String referenceNumber) {
        Transaction transaction = transactionRepository.findByReferenceNumber(referenceNumber)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction not found with reference: " + referenceNumber));
        return TransactionResponse.fromEntity(transaction);
    }

    @Transactional(readOnly = true)
    public TransactionResponse getTransactionById(Long id) {
        Transaction transaction = transactionRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction not found with ID: " + id));
        return TransactionResponse.fromEntity(transaction);
    }

    @Transactional(readOnly = true)
    public Page<TransactionResponse> getUserTransactions(Long userId, Pageable pageable) {
        return transactionRepository.findByUserId(userId, pageable).map(TransactionResponse::fromEntity);
    }

    @Transactional(readOnly = true)
    public Page<TransactionResponse> getUserTransactionsByType(Long userId, TransactionType type, Pageable pageable) {
        return transactionRepository.findByUserIdAndTransactionType(userId, type, pageable)
                .map(TransactionResponse::fromEntity);
    }

    @Transactional(readOnly = true)
    public List<TransactionResponse> getUserTransactionsBetweenDates(Long userId, LocalDateTime startDate, LocalDateTime endDate) {
        return transactionRepository.findUserTransactionsBetweenDates(userId, startDate, endDate)
                .stream()
                .map(TransactionResponse::fromEntity)
                .collect(Collectors.toList());
    }

    @Transactional(readOnly = true)
    public BigDecimal getUserTotalByType(Long userId, TransactionType type) {
        BigDecimal total = transactionRepository.sumCompletedAmountByUserAndType(userId, type);
        return total != null ? total : BigDecimal.ZERO;
    }

    @Transactional(readOnly = true)
    public Page<TransactionResponse> getRecentTransactions(Long userId, Pageable pageable) {
        return transactionRepository.findRecentTransactions(userId, pageable)
                .map(TransactionResponse::fromEntity);
    }

    @Transactional
    public TransactionResponse cancelTransaction(Long transactionId) {
        Transaction transaction = transactionRepository.findById(transactionId)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction not found with ID: " + transactionId));

        if (transaction.getStatus() != TransactionStatus.PENDING) {
            throw new TransactionProcessingException("Only pending transactions can be cancelled");
        }

        transaction.setStatus(TransactionStatus.CANCELLED);
        Transaction savedTransaction = transactionRepository.save(transaction);
        return TransactionResponse.fromEntity(savedTransaction);
    }

    @Transactional
    public void cleanupStaleTransactions(int hoursOld) {
        LocalDateTime cutoff = LocalDateTime.now().minusHours(hoursOld);
        List<Transaction> staleTransactions = transactionRepository.findStaleTransactions(TransactionStatus.PENDING, cutoff);

        for (Transaction transaction : staleTransactions) {
            transaction.setStatus(TransactionStatus.FAILED);
            transaction.setFailureReason("Transaction timed out after " + hoursOld + " hours");
        }

        transactionRepository.saveAll(staleTransactions);
        logger.info("Cleaned up {} stale transactions", staleTransactions.size());
    }

    private String generateReferenceNumber() {
        return "TXN-" + UUID.randomUUID().toString().replace("-", "").substring(0, 16).toUpperCase();
    }
}


